var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"너희는 서둘러 도시를 탈출해라.","JPN":"君たちは急いで都市から脱出しろ。","ENG":"You should hurry and escape the city.","TWN":"你們兩個迅速撤出城市。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"나는 이곳에서 끝을 보겠다.","JPN":"私はここで決着をつける。","ENG":"I will see how this ends here.","TWN":"我會在這裡結束一切。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"만트라 코드를 잊어버린 지금, 놈을 상대할 수 있는 건 나뿐이다.","JPN":"マントラコードを忘れた今、やつの相手をできるのは私だけだ。","ENG":"With the mantra code forgotten, the only one who can deal with it is me.","TWN":"既然已經記不得曼陀羅代碼，那能對付那傢伙的就只有我。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"음? 그건 좀 힘들겠는데?","JPN":"ん？　それは難しいぞ。","ENG":"Hmm? That's not going to happen.","TWN":"嗯？恐怕有點困難。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"내가 허락 안 해줄 거거든.\xA0","JPN":"俺が許可しないからな。\xA0","ENG":"Because I won't allow it.\xA0","TWN":"因為我可不同意。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"윽……! 공간이 제멋대로……! ","JPN":"うっ……！　勝手に空間が……！ ","ENG":"Ngh...! The space is doing it again...!","TWN":"呃……！空間在變化……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"움직일 수 없어……?","JPN":"動けない……？","ENG":"I can't move...?","TWN":"沒辦法動……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"라비! 이게 무슨 짓이지?","JPN":"ラビ！　何のつもりだ？","ENG":"Ravi! What's the meaning of this?","TWN":"你在做什麼？拉維！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"내 CRF를 억지로 뽑아내서 차원 닻으로 내보낼 수 있는 인원은 한 명이 한계야.","JPN":"俺のCRFを無理やり引き抜いても、次元錨で送れる人数は精々一人までだ。","ENG":"Squeezing every ounce of CRF in me, I can only send one person by the Dimension Anchor.","TWN":"就算用光我所有的CRF，也只能用次元錨送出去一個人。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"지휘관은 귀중한 자원이니, 우리가 나서서 시간을 끌어야 하지 않겠나?","JPN":"指揮官は貴重な資源だから、俺たちが時間を稼ぐべきだろう。","ENG":"Commanders are a valuable asset, so don't you think we should step in and buy you some time?","TWN":"戰隊長是寶貴的資源，應該由我們來拖延時間，不是嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"말도 안 되는 소리 마라! 지휘관은 끝까지 남아 전선을 지켜야 해!","JPN":"ふざけるな！　指揮官は最後まで戦線を守らないといけない！","ENG":"Don't be ridiculous! A commander must stay at the frontlines and defend it!","TWN":"別說這種話！戰隊長必須堅守到最後，守住前線！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"그리고 저 침식체가 뭔지 잘 알고 있잖아!","JPN":"それに、あの侵食体がいったい何なのかよくわかっているだろう！","ENG":"And you know just as well as I do what that C.O. is!","TWN":"而且你很清楚那是什麼侵蝕體！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"내 부하들이야! 그리고 우리의 함선이라고! 배를 버리고 도망가는 선장은 없다!","JPN":"私の部下だ！　そして私たちの艦船なんだ！　船を捨てて逃げる船長などいない！","ENG":"They are my subordinates! And it's our ship! No captain abandons ship and runs away!","TWN":"他們是我的部下！而那是我們的艦船！船長是不會棄船而逃的！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"적어도 나는 저 녀석들과 함께해야 해! 부하를 버리고 혼자 살아남는 비겁자가 되라는 건가?!","JPN":"少なくとも私はあいつらと一緒にいなければならない！　部下を見捨てて一人生き残る卑怯者になれというのか！？","ENG":"I must at least be with them! Or do you want me to become a coward who left my subordinates and survived alone?!","TWN":"至少我得和他們在一起！你是要我拋棄部下，自己一個人苟且偷生嗎？！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"아샤에게 안부나 전해줘. 아마 때가 되면 널 찾아올 거야.","JPN":"アーシャによろしく伝えてくれ。恐らく、時が来ればお前を訪ねてくるだろうさ。","ENG":"Say hello to Asha for me. She'll come find you when the time is right.","TWN":"替我向阿莎問好。或許時機成熟時，她會來找你。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"많이 힘들어할 테니까…… 나 대신 아샤를 지켜줘.","JPN":"とてもつらいと思うから……俺の代わりにアーシャを守ってくれ。","ENG":"She'll have been through a lot, so... protect Asha for me.","TWN":"那孩子一個人會很辛苦……請替我保護好她。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"아샤는…… 네가 지키면 되는 거잖아…… 아닐라, 너도…… 어서……!","JPN":"アーシャは……君が守ればいいだろう……アニラ、君も……早く……！","ENG":"You can... protect Asha yourself... Anila, you too... Hurry...!","TWN":"阿莎……你自己保護吧……雅妮拉，你也一樣……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"당장 공간 제어를 멈춰라! 이건…… 명령 불복종이다!","JPN":"今すぐ空間制御を止めろ！　これは……命令不服従だぞ！","ENG":"Stop controlling the space this instant! You are... disobeying direct orders!","TWN":"馬上解開空間控制！你這是……違抗命令！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하. 저희는 침식체 내부에서 작전을 수행하겠습니다.","JPN":"あはは。私たちは侵食体の内部で作戦を遂行します。","ENG":"Ah hah hah. We'll continue the operation from within the C.O.","TWN":"呵呵呵，我們會繼續在侵蝕體體內執行任務的。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님이 우릴 내보내고 싸우려는 이유도 힘을 제어할 방법을 잊었기 때문이잖아요.","JPN":"アーディティヤ様が私たちを外に出して戦おうとしている理由も、力を制御する方法を忘れているからでしょう？","ENG":"Miss Aditya, you're trying to push us out and fight alone because you've forgotten how to control your powers.","TWN":"你之所以要把我們送走自己留下來作戰，也是因為忘記控制力量的方法吧？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저도 많은 기억을 잃었어요.","JPN":"私もたくさんの記憶を失いました。","ENG":"I've also lost a lot of memories.","TWN":"我也喪失很多記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"제 이름이 뭐였는지…… 우리 전대가 어떤 임무를 수행했는지…… 전부 다요.","JPN":"自分の名前は何だったのか……私たちの戦隊がどんな任務を遂行してきたのか……そのすべてを。","ENG":"What my name was... What missions our division performed... All of it.","TWN":"我叫什麼名字……小隊在執行什麼任務……我全都不記得。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"……당신의 이름 조차도요. 아디트야 님.","JPN":"……あなたの名前さえもです。アーディティヤ様。","ENG":"...Even your name, Miss Aditya.","TWN":"……甚至是你的名字，阿迪亞。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"그러니 더더욱 내가 나서야 한다! 너희 둘이 나섰다간 개죽음일 뿐이야!","JPN":"だったらなおさら私が行くべきだ！　君たち二人で行ったら犬死にするだけだぞ！","ENG":"That's why I must do it! You two will meet your deaths if you go!","TWN":"所以更需要讓我來！你們兩個去只會白白送死！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"지금 상태로는 바루나스트라를 못 잡는다는 거, 알고 계시잖아요.","JPN":"今の状態ではヴァルナストラを倒せないということはご存じでしょう？","ENG":"You know that you cannot defeat Varunastra in your current state too.","TWN":"你知道以現在的狀態是討伐不了伐樓拿之艦的吧？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그러니 우리는 어떻게든 안쪽에서 격퇴하는 방법을 찾겠습니다.","JPN":"ですから、私たちはなんとか内側から撃退する方法を見つけます。","ENG":"So, we'll try to find a way to defeat it from inside it.","TWN":"所以我們會想辦法從內部下手。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아디트야의 말대로, 이대로 있다간 개죽음일 뿐이에요.","JPN":"アーディティヤ様の言うとおり、このままでは犬死にするだけです。","ENG":"Like you said, Miss Aditya. If this continues, we'll all die.","TWN":"正如你所說的，這樣下去只會白白送死。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"우리 신호가 끊겼으니 카멜롯 전대가 도착할 거다. 힘들겠지만, 조금만 참아라.","JPN":"俺たちの信号が途絶えているから、キャメロット戦隊が来るはずだ。苦しいと思うが、もう少しの辛抱だぞ。","ENG":"The Camelot Division will soon be here after our signal got cut off. It'll be hard, but be patient.","TWN":"我們的信號斷了，所以卡梅羅戰隊會來找我們的。雖然很艱難，但再撐一下。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"둘 정도라면 어떻게든 빠져나갈 수 있어.","JPN":"二人だけならなんとか抜け出せるはずだ。","ENG":"The two of you can get out of here.","TWN":"只有你們兩個的話，還逃得掉的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"제발…….","JPN":"だから……","ENG":"So, please...","TWN":"拜託……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"너희라도 도망치라고…….","JPN":"君たちだけでも逃げてくれ……","ENG":"Go before it's too late...","TWN":"你們快逃……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"작별 시간이네요. ","JPN":"お別れの時間ですね。 ","ENG":"It's time to say goodbye.","TWN":"離別的時間到了。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이걸로 은혜를 다 갚기엔 좀 모자란데. 아하하.","JPN":"恩返しするにはこれでも足りないけどなぁ。あはは。","ENG":"Although it's not enough to repay what you've done for me. Ah hah hah.","TWN":"即使我們做這些也無法報答你的恩情，呵呵呵。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"어떻게든 살아있어야겠네요. 그렇죠?","JPN":"なんとか生き延びなくちゃ。そうでしょう？","ENG":"So, I'll have to stay alive somehow, right?","TWN":"所以無論如何都要想辦法活下去，對吧？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"물론이다. 다시 보는 날이 온다면 아샤랑 둘이서 손잡고 와라.","JPN":"もちろんだ。また会える日が来たら、アーシャと二人で手繋いで来い。","ENG":"Of course. If the day comes when we see each other again, you can come with Asha.","TWN":"當然。如果還有機會再見，記得帶著阿莎一起來。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"이대론 계속 화만 낼 테니 잠깐 기절이나 시켜줘.","JPN":"このままだとずっと怒ってばかりだろうから、ちょっと気絶させてやってくれ。","ENG":"Knock her out cold or she'll throw a fit again.","TWN":"還是把她弄暈吧，否則她只會一直拒絕我們。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"……그편이 서로에게 좋을 테니까.","JPN":"……そのほうがお互い楽だろうからな。","ENG":"...That will be better for all of us.","TWN":"……這樣對大家都好。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"언제가 됐든 저는 기다릴게요. 그러니 그런 표정 짓지 마세요.","JPN":"そんな顔しなくてもいいですよ。いつまでも待ってますから。","ENG":"I'll be waiting for you, no matter how long it takes. So, don't make that face.","TWN":"無論什麼時候，我都會等你的。所以不要露出那樣的表情。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_7"},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"<color=#ffd34c> 앞으로 나아가세요. </color>","JPN":"<color=#ffd34c>だから、前に進んでください。</color>","ENG":"<color=#ffd34c>So, move forth</color>.","TWN":"<color=#ffd34c>所以，向前進吧。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_8"},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"모두의 의지를 이어받아서.","JPN":"みんなの意志を受け継いで。","ENG":"With everyone's will with you.","TWN":"承載著所有人的意志。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_9"},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하. 오랜만이에요. 제가 또 약속을 하면 지키는 사람…….","JPN":"あはは。お久しぶりです。私は約束をちゃんと守る人……","ENG":"Ah hah hah. Long time no see. See? I'm good at keeping promises–","TWN":"呵呵呵，好久不見。你看，我有遵守約定吧……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"명령 불복종에 대한 처벌은…… 없던 걸로 하지.","JPN":"命令不服従への罰は……なかったことにしょう。","ENG":"Your punishment for disobeying my orders... will be dismissed.","TWN":"抗命的懲罰……現在一筆勾銷。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하. 말씀하신 내용과 행동이 너무 다른 걸요? 이렇게 안아 주실 줄이야.","JPN":"あはは。言っている内容と行動が一致しませんよ。こうしてハグしてくださるなんて。","ENG":"Ah hah hah. Your words and your actions don't seem to match. Your hugging me was the last thing I expected.","TWN":"呵呵呵，你說的怎麼和做的相反？我快要被你給勒死咧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저기, 감격의 상봉 중에 죄송하지만, 저 침식체 잡을 수는 있는 거죠?","JPN":"あの、涙の再会の途中にすみません。あの侵食体、倒せるんですよね？","ENG":"Um, sorry to bother the two of you during this heartwarming reunion, but we can now defeat that C.O., right?","TWN":"那個，很抱歉打擾你們的感人重逢，但能解決一下那個侵蝕體嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"물론이다. 더 이상 질질 끌 생각은 없어.","JPN":"もちろんだ。これ以上引きずるつもりはない。","ENG":"Of course. I don't plan on dragging this out any longer.","TWN":"當然，我要結束這場歹戲。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……그렇지, 라비?","JPN":"……だろう？　ラビ。","ENG":"...Isn't that right, Ravi?","TWN":"……對吧，拉維？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"약속은 제대로 지켰군그래. 아샤랑 둘이서 찾아오다니.","JPN":"約束はちゃんと守ったんだな。アーシャと二人でやってくるとは。","ENG":"You came back with Asha. Just like you promised.","TWN":"你果然有遵守約定，帶著阿莎一起來。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_27"},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"뭐 하고 있지? 아직 지켜야 할 사람들이 남아 있잖나?","JPN":"何をしている？　まだ守らなければならない者たちが残っているだろう？","ENG":"What are you doing? There are still people left to save.","TWN":"你在做什麼？你還有需要保護的人不是嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"당장 네가 해야 할 일을 해야지.","JPN":"お前は、お前のやるべきことをすればいい。","ENG":"Do what you came here to do.","TWN":"去做你該做的事。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그럼에도, 앞으로 나아가는 것.","JPN":"それでも、前に進むこと。","ENG":"Yet, we go forth.","TWN":"然後繼續向前。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"죽어서도 입바른 소리로군. 역시 이게 당신다워, 라비 부전대장.","JPN":"歯に衣着せぬ物言いは死んでも同じか。さすが君らしい、ラビ副戦隊長。","ENG":"Always knowing the right words to say even in death. This is more like you, Deputy Commander Ravi.","TWN":"人都死了嘴巴還不饒人。不過這才像你，拉維副戰隊長。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그럼…… 못다 한 임무를 마무리 지어 볼까?","JPN":"では……やり残した任務を完遂しに行くか。","ENG":"Then... shall we go finish our mission?","TWN":"那麼……來完成未完成的任務吧？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"만트라 코드. 사비트르 활성화.","JPN":"マントラコード。サヴィトリ活性化。","ENG":"Activating mantra code, Savitr.","TWN":"曼陀羅代碼，娑維德利，啟動。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>만트라 코드: 사비트르</color> 활성화.","JPN":"<color=#ffd34c>マントラコード：サヴィトリ</color>活性化。","ENG":"Activating <color=#ffd34c>mantra code: Savitr</color>.","TWN":"<color=#ffd34c>曼陀羅代碼：娑維德利</color> ，啟動。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"생체 인식 코드 일치 확인.","JPN":"生体認識コードの一致を確認。","ENG":"Biometric authentication verified.","TWN":"生物識別代碼已匹配。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국 고유 무장: <color=#ffd34c>수리야스트라</color> 시동.","JPN":"管理局固有武装：<color=#ffd34c>スーリヤストラ</color>始動。","ENG":"Activating Administration Unique Gear: <color=#ffd34c>Suryastra</color>.","TWN":"管理局專屬武裝：<color=#ffd34c>蘇利耶法寶</color> 啟動。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"정화전대 바루나의 전대장 수리야! 작전 수행 불능으로 보류되었던 임무를 재개한다.","JPN":"浄化戦隊ヴァルナの戦隊長、スーリヤ！　作戦遂行不能で保留にされていた任務を再開する。","ENG":"Surya, Commander of the Purification Division Varuna! Resuming mission that was put on hold due to inability to carry out operations.","TWN":"這裡是伐樓拿淨化戰隊隊長蘇利亞！現在重啟因無法執行而擱置的任務！"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_1"},{"id":"L23_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"정화 목표는 미상 타입의 침식체 바루나스트라!","JPN":"浄化目標は詳細不明の侵食体ヴァルナストラ！","ENG":"The purification target is the unidentified type C.O., Varunastra!","TWN":"淨化目標為未知類型的侵蝕體，伐樓拿之艦！"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_2"},{"id":"L24_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"대원들의 머릿속에, 귓가에, 눈 앞에 그리운 사람이 나타나 대원들을 현혹할 수 있다.","JPN":"やつは脳内、耳元、目の前に恋しい人物を出現させ、隊員たちを惑わせてくる。","ENG":"A person you have been longing for might appear inside your head, your ears, or in front of your eyes to allure you.","TWN":"各位隊員記住，作戰中出現的任何思念之人的聲音、影像與幻影，都有可能是敵人的迷惑手段！"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_3"},{"id":"L25_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"허나 기억하라. 우리는 모든 것을 잃었다는 것을.","JPN":"だが、覚えておけ。私たちはすべてを失ったということを。","ENG":"But remember. We have lost everything.","TWN":"請記住，我們已失去一切。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_4"},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"우리는…… 그럼에도 일어서야 한다는 것을.","JPN":"私たちは……それでも立ち上がらなければならないということを。","ENG":"Despite this… we must get back up.","TWN":"儘管如此……我們也要站起來。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_5"},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"나는 너희의 어둠을 밝히는 태양이자 타오르는 검이니, 눈앞의 어둠을 두려워하지 마라.","JPN":"私は君たちの闇を照らす太陽であり、燃え上がる剣である。故に目の前の闇を恐れるな。","ENG":"I am the sun that illuminates your darkness, and your flaming sword! Do not be afraid of the darkness before you!","TWN":"我是照亮你們黑暗的太陽，也是把燃燒的劍，不要畏懼眼前的黑暗"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_7"},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"바루나 전대! 명령을 하달한다!","JPN":"ヴァルナ戦隊！　命令を皆に伝える！","ENG":"Varuna Division! I command you!","TWN":"伐樓拿戰隊！全體聽令！"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_8"},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"어둠을 정화하고, 앞으로 나아가라!","JPN":"闇を浄化し、前に進め！","ENG":"Purify the evil, and move forth!","TWN":"淨化黑暗，向前進！"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_9"}]`);export{e as default};